features.snippet:
parameter WIDTH = 8192;
output [WIDTH-1 : 0] out;
input clk, reset;
reg [WIDTH-1 : 0] out;
always @(posedge clk or posedge reset)
  if (reset)
    out <= 0;
  else
    out <= out + 1;

cell(COUNTER) {
  ff("IQ", "IQN") { clocked_on: Q0; next_state: Q1; clear: R; }
  ff("IQ", "IQN") { clocked_on: Q1; next_state: Q2; clear: R; }
  pin(C) { direction: input; clock: true; }
  pin(Q0) { direction: output; function: "IQ"; }
  pin(Q1) { direction: output; function: "IQ"; }
  pin(R) { direction: input; }
}
